INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'lubbock'), 'RE', 're', 'Residential Estates', 'Provides for very low-density residential neighborhoods with on-site utilities, preserving rural low-density character and allowing for large animals. It also includes a cluster option for residential neighborhoods with a high percentage of common open space to maintain rural character.', 45, NULL, 87120, 50, 60, 30, 20, 'Refer to UDC Table 39.03.009-2 Off-Street Parking and Loading Schedule.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
INSERT INTO zone_permitted_uses (zone_id, permitted_use_id) SELECT z.id, pu.id FROM zones z, permitted_uses pu WHERE z.zone_code_slug = 're' AND z.city_id = (SELECT id FROM cities WHERE slug = 'lubbock') AND pu.name IN ('Agricultural Uses', 'Community Garden', 'Farm, Ranch, or Orchard', 'Single-Family Detached Dwelling', 'Industrialized Housing', 'Utilities', 'Water Storage', 'Storm Shelter') ON CONFLICT DO NOTHING;
